from langflow.custom import Component
from langflow.io import DataInput, Output
import json

class JiraSearchParserComponent(Component):
    display_name = "Jira Search Parser"
    description = "Parses the JIRA search response JSON to extract key, summary, type, description, and priority."

    inputs = [
        DataInput(
            name="jira_json",
            display_name="Jira JSON Response",
            info="The JSON output from the API Request component"
        )
    ]

    outputs = [
        Output(display_name="Parsed Text", name="parsed_text", types=["Message"], method="build_output"),
    ]


    def build_output(self) -> str:
        jira_json = self.jira_json

        if not jira_json:
            return "No data received."
            
        def flatten_adf(node):
            if not node: return ""
            if isinstance(node, str): return node
            if isinstance(node, list): return "".join(flatten_adf(n) for n in node)
            text = ""
            if node.get("type") == "text":
                text += node.get("text", "")
            if "content" in node:
                text += flatten_adf(node["content"])
            if node.get("type") in ["paragraph", "heading", "listItem", "blockquote", "bulletList", "orderedList"]:
                text += "\n"
            if node.get("type") in ["hardBreak", "rule"]:
                text += "\n"
            return text

        try:
            # Extract data from Langflow structure if wrapped
            data = jira_json
            if hasattr(jira_json, "data"):
                data = jira_json.data
            elif isinstance(jira_json, str):
                try:
                    data = json.loads(jira_json)
                except json.JSONDecodeError:
                    pass
            
            # If the response is wrapped inside Langflow's API Request structure, get "result"
            if isinstance(data, dict) and "result" in data:
                data = data["result"]
            
            # If it's still a string (nested json parsing)
            if isinstance(data, str):
                data = json.loads(data)

            issues = data.get("issues", [])
            if not issues:
                return "No issues found in the JIRA response."
                
            formatted_issues = []
            for issue in issues:
                key = issue.get("key", "Unknown Key")
                fields = issue.get("fields", {})
                summary = fields.get("summary", "No Summary")
                
                # Extract issuetype name
                issue_type = fields.get("issuetype", {})
                type_name = issue_type.get("name", "Unknown Type") if isinstance(issue_type, dict) else "Unknown Type"
                
                # Extract priority name
                priority = fields.get("priority", {})
                priority_name = priority.get("name", "Unspecified") if isinstance(priority, dict) else "Unspecified"
                
                # Extract and flatten ADF description
                desc = fields.get("description", "")
                if isinstance(desc, dict):
                    desc = flatten_adf(desc)
                elif not desc:
                    desc = "No description provided."
                
                formatted_issues.append(
                    f"### ISSUE: {key}\n"
                    f"**Summary:** {summary}\n"
                    f"**Type:** {type_name}\n"
                    f"**Priority:** {priority_name}\n"
                    f"**Description:**\n{desc.strip()}\n"
                )
            
            output = "\n---%---\n".join(formatted_issues)
            self.status = output
            return output
        except Exception as e:
            return f"Error parsing JIRA data: {str(e)}"

from langflow.custom import Component
from langflow.io import FileInput, Output
import os

class LocalDocumentReaderComponent(Component):
    display_name = "Local Document Reader"
    description = "Reads text from PDF, DOCX, TXT, MD, or JSON files locally. 100% free and offline."

    inputs = [
        FileInput(
            name="file_path",
            display_name="File",
            info="Upload a PDF, DOCX, TXT, MD, or JSON file",
            file_types=["pdf", "docx", "txt", "md", "json"]
        )
    ]

    outputs = [
        Output(display_name="Text Output", name="text_output", types=["Message"], method="read_document"),
    ]


    def read_document(self) -> str:
        if not self.file_path:
            return ""
        path = self.file_path.strip()

            
        if not os.path.exists(path):
            return f"Error: File not found at path: {path}"

        ext = os.path.splitext(path)[1].lower()

        # Handle PDF
        if ext == ".pdf":
            try:
                import pypdf
                reader = pypdf.PdfReader(path)
                text_pages = []
                for i, page in enumerate(reader.pages):
                    page_text = page.extract_text()
                    if page_text:
                        text_pages.append(f"--- PAGE {i+1} ---\n{page_text}")
                if not text_pages:
                    return "Successfully read PDF, but no extractable text was found (possibly a scanned image PDF)."
                return "\n\n".join(text_pages)
            except Exception as e:
                return f"Error reading PDF: {str(e)}"

        # Handle DOCX
        elif ext == ".docx":
            try:
                import docx
                doc = docx.Document(path)
                paragraphs_text = [p.text for p in doc.paragraphs if p.text.strip()]
                
                # Also extract text from any tables in the Word doc
                table_text = []
                for table in doc.tables:
                    for row in table.rows:
                        row_cells = [cell.text.strip() for cell in row.cells if cell.text.strip()]
                        if row_cells:
                            table_text.append(" | ".join(row_cells))
                
                full_text = paragraphs_text + table_text
                if not full_text:
                    return "Successfully read DOCX, but document is empty."
                return "\n\n".join(full_text)
            except ImportError:
                return "Error: `python-docx` is not installed. Run `pip install python-docx` in your environment to enable DOCX parsing."
            except Exception as e:
                return f"Error reading DOCX: {str(e)}"

        # Handle Text / MD / JSON
        elif ext in [".txt", ".md", ".json"]:
            try:
                with open(path, "r", encoding="utf-8") as f:
                    content = f.read()
                if not content.strip():
                    return f"File is empty: {path}"
                return content
            except Exception as e:
                return f"Error reading text file: {str(e)}"

        else:
            return f"Unsupported file format: '{ext}'. Supported formats are: .pdf, .docx, .txt, .md, .json"

import re
import os
from langflow.custom import Component
from langflow.io import MessageTextInput, Output

class MultiFileWriterComponent(Component):
    display_name = "Multi-File Writer"
    description = "Parses the LLM response and extracts test_plan.md and test_strategy.md files into the exports folder."

    inputs = [
        MessageTextInput(
            name="llm_output",
            display_name="LLM Output",
            info="The raw text response from the LLM component",
            value=""
        )
    ]

    outputs = [
        Output(display_name="Write Status", name="write_status", types=["Message"], method="write_files"),
    ]

    def write_files(self) -> str:
        text = self.llm_output
        if not text:
            return "No content to write."

        export_dir = "/app/langflow/exports"
        try:
            os.makedirs(export_dir, exist_ok=True)
        except Exception:
            pass

        # Regex to extract text between delimiters
        plan_match = re.search(r"=====START OF test_plan\.md=====(.*?)=====END OF test_plan\.md=====", text, re.DOTALL)
        strategy_match = re.search(r"=====START OF test_strategy\.md=====(.*?)=====END OF test_strategy\.md=====", text, re.DOTALL)

        status_messages = []

        if plan_match:
            plan_content = plan_match.group(1).strip()
            plan_path = os.path.join(export_dir, "test_plan.md")
            try:
                with open(plan_path, "w", encoding="utf-8") as f:
                    f.write(plan_content)
                status_messages.append(f"✅ **Test Plan** written to `{plan_path}`")
            except Exception as e:
                status_messages.append(f"❌ Failed to write **Test Plan**: {str(e)}")
        else:
            status_messages.append("⚠️ Could not locate a valid `=====START OF test_plan.md===== ... =====END OF test_plan.md=====` block in the LLM response.")

        if strategy_match:
            strategy_content = strategy_match.group(1).strip()
            strategy_path = os.path.join(export_dir, "test_strategy.md")
            try:
                with open(strategy_path, "w", encoding="utf-8") as f:
                    f.write(strategy_content)
                status_messages.append(f"✅ **Test Strategy** written to `{strategy_path}`")
            except Exception as e:
                status_messages.append(f"❌ Failed to write **Test Strategy**: {str(e)}")
        else:
            status_messages.append("⚠️ Could not locate a valid `=====START OF test_strategy.md===== ... =====END OF test_strategy.md=====` block in the LLM response.")

        status_messages.append("💡 *These files will be synced to your host machine at:* \n`D:\\ai_3x_qa\\QA_AI_Projects\\AI_tools\\langflow-agents\\langflow-data\\exports\\`")
        return "\n\n".join(status_messages)

